    | sqlgen::where("user_id"_t3.is_null());

  // Execute all queries and collect results
  auto mutual_results = mutual_friends_query(conn);
  auto avg_results = avg_friends_query(conn);
  auto friend_of_friend_results = friend_of_friend_query(conn);
  auto most_connected_results = most_connected_query(conn);
  auto recommendation_results = recommendation_query(conn);

  // Process mutual friends results
