  (sqlgen::insert_into<Employee>(emps))(conn);

  // Perform INNER JOIN
  auto inner_query = sqlgen::select_from<Department, "d">("department_name"_t1, "first_name"_t2, "last_name"_t2, "salary"_t2)
                   | sqlgen::inner_join<Employee, "e">("department_id"_t1 == "department_id"_t2);
  auto inner_results = sqlgen::internal::collect::vector(inner_query(conn));

  // Perform LEFT JOIN
  auto left_query = sqlgen::select_from<Employee, "e">("first_name"_t2, "last_name"_t2, "salary"_t2, "department_name"_t1)
                   | sqlgen::left_join<Department, "d">("department_id"_t2 == "department_id"_t1);
  auto left_results = sqlgen::internal::collect::vector(left_query(conn));

  // Perform RIGHT JOIN
  auto right_query = sqlgen::select_from<Department, "d">("department_name"_t1, "first_name"_t2, "last_name"_t2, "salary"_t2)
                   | sqlgen::right_join<Employee, "e">("department_id"_t1 == "department_id"_t2);
  auto right_results = sqlgen::internal::collect::vector(right_query(conn));

  // Perform FULL JOIN
  auto full_query = sqlgen::select_from<Department, "d">("department_name"_t1, "first_name"_t2, "last_name"_t2, "salary"_t2)
                   | sqlgen::full_join<Employee, "e">("department_id"_t1 == "department_id"_t2);
  auto full_results = sqlgen::internal::collect::vector(full_query(conn));

  // Convert results to JoinResult format
  auto to_join_result = [](auto&&... fields) -> JoinResult {
    return JoinResult{
        .department_name = std::get<0>(fields),
        .first_name = std::get<1>(fields),
        .last_name = std::get<2>(fields),
        .salary = std::get<3>(fields)
    };
  };

  // Map results to JoinAnalysis structure
  JoinAnalysis analysis;
  analysis.inner_join_results = sqlgen::internal::collect::vector(
      inner_results | std::views::transform(to_join_result));

  analysis.left_join_results = sqlgen::internal::collect::vector(
      left_results | std::views::transform(to_join_result));

  analysis.right_join_results = sqlgen::internal::collect::vector(
      right_results | std::views::transform(to_join_result));

  analysis.full_join_results = sqlgen::internal::collect::vector(
      full_results | std::views::transform(to_join_result));

  return analysis;
}

}  // namespace analyze_department_employees
