  sqlgen::PrimaryKey<int> sale_id;
  int product_id;
  int quantity;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> sale_time;
};

struct WeekdayStats {
  int weekday;
  int total_quantity;
};

/**
 * Description: This function analyzes sales data to calculate total quantity sold for each weekday.
 * Returns: std::vector<WeekdayStats>.
 */
std::vector<WeekdayStats> weekday_sales_analysis() {
  // Connect to the database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite").value();

  // Retrieve Sales data from the database
  auto sales_result = sqlgen::read<std::vector<Sales>>(conn).value();

  // Create a map to accumulate weekday totals
  std::map<int, int> weekday_totals;

  // Initialize all weekdays (1=Monday to 7=Sunday)
  for (int i = 1; i <= 7; ++i) {
    weekday_totals[i] = 0;
  }

  // Process each sale to extract weekday and accumulate quantities
  for (const auto& sale : sales_result) {
    // Extract weekday from sale_time (assuming Timestamp provides string representation)
    std::istringstream ss(sale.sale_time.str());
    std::tm tm = {};
    ss >> std::get_time(&tm, "%Y-%m-%d %H:%M:%S");

    // Convert tm_wday (0=Sunday, 6=Saturday) to 1=Monday to 7=Sunday
    int weekday = (tm.tm_wday == 0) ? 7 : tm.tm_wday + 1;

    // Accumulate quantity for the corresponding weekday
    weekday_totals[weekday] += sale.quantity;
  }

  // Convert the map to a sorted vector of WeekdayStats
  std::vector<WeekdayStats> result;
  for (const auto& [weekday, total] : weekday_totals) {
    result.push_back({weekday, total});
  }

  // Sort by weekday in ascending order
  std::sort(result.begin(), result.end(), 
              [](const WeekdayStats& a, const WeekdayStats& b) {
                return a.weekday < b.weekday;
              });

  return result;
}

}  // namespace weekday_sales_analysis

